// Bicep: deploy a storage account with governance controls baked in
@description('Environment name for tagging')
param environment string = 'prod'

@description('Team owner email')
param ownerEmail string

var saName = 'sa${uniqueString(resourceGroup().id)}'

resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: saName
  location: resourceGroup().location
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
  tags: {
    Environment: environment
    Owner: ownerEmail
    CostCenter: 'engineering'
    DataClassification: 'Internal'
  }
  properties: {
    supportsHttpsTrafficOnly: true      // Enforce HTTPS — no HTTP
    minimumTlsVersion: 'TLS1_2'        // No TLS 1.0/1.1
    allowBlobPublicAccess: false        // No anonymous blob access
    networkAcls: { defaultAction: 'Deny', bypass: 'AzureServices' }
  }
}

// Resource lock — no deletion without explicit lock removal + audit trail
resource saLock 'Microsoft.Authorization/locks@2020-05-01' = {
  name: '${saName}-lock'
  scope: storageAccount
  properties: { level: 'CanNotDelete', notes: 'Production data' }
}

output storageAccountId string = storageAccount.id
